     3|const RATE_LIMIT_WINDOW_MS = 60 * 60 * 1000
     4|const RATE_LIMIT_MAX = 10
     5|const ipBuckets = new Map<string, { count: number; resetAt: number }>()
     6|
     7|const HUBSPOT_PORTAL_ID = process.env.CRM_PORTAL_ID || 'HS-PORTAL-PARAGUAI'
     8|const HUBSPOT_FORM_ID = process.env.CRM_ENDPOINT || 'contact-form-paragu-ai'
     9|const HUBSPOT_API_URL = `https://api.hsforms.com/submissions/v3/integration/secure/submit/${HUBSPOT_PORTAL_ID}/${HUBSPOT_FORM_ID}`
    10|
    11|function getRateLimitInfo(ip: string): { allowed: boolean; remaining: number; resetAt: number } {
    12|  const now = Date.now()
    13|  const bucket = ipBuckets.get(ip)
    14|  if (!bucket || now > bucket.resetAt) {
    15|    ipBuckets.set(ip, { count: 1, resetAt: now + RATE_LIMIT_WINDOW_MS })
    16|    return { allowed: true, remaining: RATE_LIMIT_MAX - 1, resetAt: now + RATE_LIMIT_WINDOW_MS }
    17|  }
    18|  const allowed = bucket.count < RATE_LIMIT_MAX
    19|  if (allowed) bucket.count++
    20|  return { allowed, remaining: Math.max(0, RATE_LIMIT_MAX - bucket.count), resetAt: bucket.resetAt }
    21|}
    22|
    23|export async function POST(request: NextRequest) {
    24|  try {
    25|    const ip = request.headers.get('x-forwarded-for')?.split(',')[0]?.trim() || request.headers.get('x-real-ip') || 'unknown'
    26|    const { allowed, remaining, resetAt } = getRateLimitInfo(ip)
    27|    if (!allowed) {
    28|      return NextResponse.json(
    29|        { error: 'Too many requests. Try again later.', retryAfter: Math.ceil((resetAt - Date.now()) / 1000) },
    30|        { status: 429, headers: { 'Retry-After': String(Math.ceil((resetAt - Date.now()) / 1000)) } }
    31|      )
    32|    }
    33|
    34|    const body = await request.json()
    35|    const { name, email, phone, message, program } = body
    36|
    37|    // Send to HubSpot
    38|    const hubspotPayload = {
    39|      fields: [
    40|        { name: 'firstname', value: name || '' },
    41|        { name: 'email', value: email || '' },
    42|        { name: 'phone', value: phone || '' },
    43|        { name: 'message', value: message || '' },
    44|        { name: 'program', value: program || '' },
    45|      ],
    46|      context: {
    47|        ipAddress: ip,
    48|        pageUri: request.headers.get('referer') || 'https://nexa.paragu-ai.com',
    49|        pageName: 'Contact Form',
    50|      },
    51|      legalConsentOptions: {
    52|        consent: {
    53|          consentToProcess: true,
    54|          text: 'I agree to be contacted',
    55|          communications: [
    56|            {
    57|              value: true,
    58|              subscriptionTypeId: 999,
    59|              text: 'I agree to receive communications',
    60|            },
    61|          ],
    62|        },
    63|      },
    64|    }
    65|
    66|    try {
    67|      const hsResponse = await fetch(HUBSPOT_API_URL, {
    68|        method: 'POST',
    69|        headers: { 'Content-Type': 'application/json' },
    70|        body: JSON.stringify(hubspotPayload),
    71|      })
    72|
    73|      if (hsResponse.ok) {
    74|        console.log('[Contact] HubSpot success:', email)
    75|        return NextResponse.json({ ok: true, remaining, hubspot: 'submitted' })
    76|      } else {
    77|        const hsError = await hsResponse.text()
    78|        console.warn('[Contact] HubSpot API error:', hsResponse.status, hsError)
    79|        // Fallback: log it so we don't lose it
    80|        console.log('[Contact] Fallback log:', JSON.stringify({ ip, name, email, phone, message, program }))
    81|        return NextResponse.json({ ok: true, remaining, hubspot: 'logged', note: 'HubSpot submission logged (check portal config)' })
    82|      }
    83|    } catch (hubspotErr) {
    84|      // HubSpot unreachable — log and return ok (don't break the form)
    85|      console.warn('[Contact] HubSpot unreachable:', String(hubspotErr))
    86|      console.log('[Contact] Fallback log:', JSON.stringify({ ip, name, email, phone, message, program }))
    87|      return NextResponse.json({ ok: true, remaining, hubspot: 'logged' })
    88|    }
    89|  } catch (err) {
