{"content": ""use client"
import { Header } from "@/components/header"
import { Footer } from "@/components/footer"
import { CartSidebar } from "@/components/cart-sidebar"
import { ProductModal } from "@/components/product-modal"
import { CookieConsent } from "@/components/cookie-consent"
import { SearchAndFilters } from "@/components/search-filters"
import { CartProvider, useCart } from "@ai-whisperers/commerce/cart/cart-context"
import { CartToastListener } from "@/components/cart-toast-listener"
import { useWishlist, useRecentlyViewed } from "@/lib/wishlist"
import { PriceUSD } from "@/components/price-usd"
import { SafeImage } from "@/components/safe-image"
import content from "@/content/es.json"
import Image from "next/image"
import Link from "next/link"
import { useState, useEffect } from "react"
import { createClient } from "@ai-whisperers/auth/supabase/client"

const c = content as any
const s = c.store || {}
const cats = c.home?.productCatalog?.categories || []
const cat = c.home?.productCatalog || {}
const staticProducts = cat.products || []
const showOutOfStock = c.home?.showOutOfStock !== false

function slugify(s: string) { return s.toLowerCase().replace(/[^a-z0-9áéíóúñü]+/g, "-").replace(/-+$/, "") }

function StockBadge({ stock }: { stock: number }) {
  if (stock === 0) return <span className="rounded-full bg-destructive/10 px-2 py-0.5 text-xs font-medium text-destructive">{s.soldOut || "Agotado"}</span>
  if (stock <= 3) return <span className="rounded-full bg-warning/10 px-2 py-0.5 text-xs font-medium text-warning">{s.lastUnits || "Últimos"} {stock}</span>
  if (stock <= 5) return <span className="rounded-full bg-amber-500/10 px-2 py-0.5 text-xs font-medium text-amber-600">{(s.remaining || "Quedan")} {stock}</span>
  return null
}

function ProductCard({ p, onClick, addItem, isWished, toggleWish }: any) {
  const parseGs = (s: string) => parseInt(s.replace(/[^\d]/g, ""), 10) || 0
  return (
    <div className="group relative overflow-hidden rounded-xl border border-border bg-surface shadow-sm transition-all hover:-translate-y-1 hover:shadow-md">
      <button
        onClick={(e) => { e.stopPropagation(); toggleWish(p.name) }}
        className="absolute right-2 top-2 z-10 flex h-8 w-8 items-center justify-center rounded-full bg-white/80 text-muted-foreground shadow-sm transition-all hover:bg-white hover:text-accent"
        aria-label={isWished(p.name) ? (ui.removeFav || "Quitar de favoritos") : (ui.addFav || "Agregar a favoritos")}
      >
        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="[REDACTED_PHONE]" fill={isWished(p.name) ? "currentColor" : "none"} stroke="currentColor" strokeWidth="2">
          <path d="M19 14c1.49-1.46 3-3.21 3-5.5A5.5 5.[REDACTED_PHONE].5 3c-1.76 0-3 .5-4.5 2-1.5-1.5-2.74-2-4.5-2A5.5 5.[REDACTED_PHONE].5c0 2.3 1.5 4.05 3 5.5l7 7Z"/>
        </svg>
      </button>
      <Link href={`/producto/${slugify(p.name)}`} onClick={() => onClick(p)}>
        <div className="aspect-[3/2] flex items-center justify-center overflow-hidden bg-muted p-4">
          {p.imageUrl ? <SafeImage src={p.imageUrl} alt={p.name} width={400} height={267} containerClassName="h-full w-full" className="h-full w-full object-contain" /> : <div className="text-center"><p className="text-xs text-muted-foreground">{s.noImage || "Sin imagen"}</p></div>}
        </div>
      </Link>
      <div className="p-4">
        <div className="mb-1 flex items-center justify-between">
          {p.brand && <span className="text-xs font-medium text-muted-foreground">{p.brand}</span>}
          {p.isNew && <span className="rounded-full bg-accent/10 px-2 py-0.5 text-[10px] font-bold text-accent">{s.new || "NUEVO"}</span>}
        </div>
        <Link href={`/producto/${slugify(p.name)}`} className="block">
          <h4 className="font-semibold text-foreground line-clamp-1 hover:text-primary transition-colors">{p.name}</h4>
          {p.specs && <p className="mt-0.5 text-[10px] text-muted-foreground/60 line-clamp-1">{p.specs}</p>}
        </Link>
        <div className="mt-2 flex items-baseline gap-2">
          <p className="text-xl font-bold text-primary">{p.price}</p>
          <PriceUSD pygStr={p.price} />
          {p.priceBefore && <p className="text-sm text-muted-foreground line-through">{p.priceBefore}</p>}
        </div>
        {p.priceBefore && <span className="mt-1 inline-block rounded-full bg-accent px-2 py-0.5 text-xs font-bold text-accent-foreground">{s.sale || "OFERTA"}</span>}
        <div className="mt-3 flex items-center gap-2">
          {p.stock !== undefined && p.stock > 0 && p.stock <= 5 && <StockBadge stock={p.stock} />}
          <button
            disabled={p.stock === 0}
            onClick={() => addItem({ id: p.id || p.slug || p.name, productId: p.id || p.slug || p.name, name: p.name, price: p.price, priceGs: parseGs(p.price), image: p.imageUrl, category: p.category, priceBefore: p.priceBefore })}
            className={`flex flex-1 items-center justify-center rounded-lg px-4 py-2.5 text-sm font-semibold transition-all ${p.stock === 0 ? "cursor-not-allowed bg-muted text-muted-foreground" : "bg-primary text-primary-foreground hover:bg-primary/90"}`}
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="[REDACTED_PHONE]" fill="none" stroke="currentColor" strokeWidth="2" className="mr-1.5"><circle cx="9" cy="21" r="1"/><circle cx="20" cy="21" r="1"/><path d="M1 1h4l2.68 13.39a[REDACTED_PHONE].61h9.72a[REDACTED_PHONE].61L23 6H6"/></svg>
            {p.stock === 0 ? (s.soldOut || "Agotado") : (s.add || "Agregar")}
          </button>
        </div>
      </div>
    </div>
  )
}

function TiendaContent() {
  const { addItem } = useCart()
  const { isWished, toggle } = useWishlist()
  const { add: addRecent } = useRecentlyViewed()
  const [cartOpen, setCartOpen] = useState(false)
  const [selectedProduct, setSelectedProduct] = useState<any>(null)
  const [filtered, setFiltered] = useState<any[] | null>(null)
  const [showOOS, setShowOOS] = useState(false)
  const [dbProducts, setDbProducts] = useState<any[]>([])
  const supabase = createClient()

  useEffect(() => {
    supabase.from("ej_products").select("*").order("name").then(({ data }) => {
      if (data && data.length > 0) {
        setDbProducts(data.map(p => ({
          name: p.name, category: p.category, price: p.price,
          priceBefore: p.price_before, description: p.description,
          brand: p.brand, specs: p.specs, stock: p.stock,
          weight: p.weight, imageUrl: p.image_url, isNew: p.is_new, featured: p.featured,
        })))
      }
    })
  }, [supabase])

  const allProducts = dbProducts.length > 0 ? dbProducts : staticProducts
  const visibleProducts = showOOS ? allProducts : allProducts.filter((p: any) => (p.stock ?? 0) > 0)
  const displayProducts = filtered ?? visibleProducts
  const handleClick = (p: any) => { addRecent(p.name); setSelectedProduct(p) }
  const groupedCats = cats.filter((cat: string) => displayProducts.some((p: any) => p.category === cat))

  return (
    <>
      <Header onCartClick={() => setCartOpen(true)} />
      <CartToastListener />
      <section className="relative overflow-hidden py-16 text-center text-primary-foreground">
        <div className="pointer-events-none absolute inset-0">
          <Image src="/images/marketing/tienda-hero-bg.png" alt="" fill className="object-cover object-center" sizes="100vw" priority />
          <div className="absolute inset-0 bg-primary/82" aria-hidden />
        </div>
        <div className="relative z-10 px-4">
          <h1 className="text-4xl font-bold">{s.title || "Tienda Online"}</h1>
          <p className="mt-2 text-primary-foreground/80">{c.tienda?.hero?.subheadline}</p>
        </div>
      </section>
      <section className="bg-surface-light py-6">
        <div className="mx-auto max-w-7xl px-4">
          <SearchAndFilters products={allProducts} categories={cats} onFilteredProducts={setFiltered} />
          <div className="mt-2 flex items-center justify-between text-xs text-muted-foreground">
            <span>{displayProducts.length} {(s.of || "de")} {allProducts.length} {(s.visible || "productos visibles")}</span>
            <label className="flex items-center gap-1.5 cursor-pointer">
              <input type="checkbox" checked={showOOS} onChange={() => setShowOOS(!showOOS)} className="rounded border-border text-primary focus:ring-primary" />
              {s.showOutOfStock || "Mostrar agotados"}
            </label>
          </div>
        </div>
      </section>
      <section className="bg-background py-16"><div className="mx-auto max-w-7xl px-4">
        {displayProducts.length === 0 && <div className="py-20 text-center"><p className="text-lg text-muted-foreground">{s.noProducts || "No encontramos productos con esos filtros."}</p></div>}
        {groupedCats.map((category: string) => (
          <div key={category} id={category.toLowerCase().replace(/[^a-z]/g, "")} className="mb-12 scroll-mt-28 last:mb-0">
            <div className="mb-6 flex items-center justify-between">
              <h2 className="text-2xl font-bold text-foreground">{category}</h2>
              <Link href={`/categoria/${category.toLowerCase().replace(/[^a-z]/g, "")}`} className="text-sm font-semibold text-primary hover:underline">{s.viewAll || "Ver todo"}</Link>
            </div>
            <div className="grid grid-cols-1 gap-6 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
              {displayProducts.filter((p: any) => p.category === category).map((p: any, i: number) => (
                <ProductCard key={i} p={p} onClick={handleClick} addItem={addItem} isWished={isWished} toggleWish={toggle} />
              ))}
            </div>
          </div>
        ))}
      </div></section>
      <Footer />
      <CartSidebar open={cartOpen} onClose={() => setCartOpen(false)} />
      <ProductModal product={selectedProduct} onClose={() => setSelectedProduct(null)} />
      <CookieConsent />
    </>
  )
}

export default function TiendaPage() {
  return (
    <CartProvider>
        <TiendaContent />
    </CartProvider>
  )
}
